module verified_d_flip_flop(rst_clk, reset, d, q);

    input rst_clk;
    input reset;
    input d;
    output q;
    reg q;
    initial q = 0;

    always @(posedge rst_clk or posedge reset)
        begin
            if (reset)
                q <= 0;
            else
                q <= d;
        end

endmodule
